"use client";

import {
  Edit,
  Eye,
  Phone,
  Plus,
  Trash2,
  UserRound,
} from "lucide-react";
import Link from "next/link";
import type { ReactNode } from "react";
import { useEffect, useMemo, useState } from "react";

import Layout from "@/components/Layout";
import {
  apiJson,
  errorMessage,
} from "@/lib/client/api";
import { notify } from "@/lib/notify";

type Teacher = {
  id: number;
  employee_id?: string | null;
  first_name?: string | null;
  last_name?: string | null;
  department?: string | null;
  designation?: string | null;
  phone?: string | null;
  email?: string | null;
  class_name?: string | null;
  section_name?: string | null;
  selected_academic_year?: string | null;
  performance_percent?: number | string | null;
  attendance_percent?: number | string | null;
  homework_completion_percent?: number | string | null;
  exam_performance_percent?: number | string | null;
  student_outcome_percent?: number | string | null;
};

const initialTeacher = {
  employee_id: "",
  first_name: "",
  last_name: "",
  phone: "",
  email: "",
  department: "",
  designation: "",
  qualification: "",
  experience_years: "",
  class_id: "",
  section_id: "",
  subject_id: "",
  assignment_type: "CLASS_TEACHER",
};

const profileFields = [
  "employee_id",
  "first_name",
  "last_name",
  "phone",
  "email",
  "department",
  "designation",
  "qualification",
  "experience_years",
] as const;

const fullName = (teacher: Teacher) =>
  [
    teacher.first_name,
    teacher.last_name,
  ]
    .filter(Boolean)
    .join(" ") || "Unnamed Teacher";

const percentValue = (
  value?: number | string | null
) => {
  const parsed = Number(value);
  return Number.isFinite(parsed)
    ? Math.max(
        0,
        Math.min(100, Math.round(parsed))
      )
    : 0;
};

const teacherPerformanceSummary = (
  teacher: Teacher
) => {
  const performance =
    percentValue(
      teacher.performance_percent
    ) ||
    Math.round(
      percentValue(
        teacher.attendance_percent
      ) * 0.3 +
        percentValue(
          teacher.homework_completion_percent
        ) * 0.3 +
        percentValue(
          teacher.exam_performance_percent
        ) * 0.2 +
        percentValue(
          teacher.student_outcome_percent
        ) * 0.2
    );

  return {
    performance,
    attendance: percentValue(
      teacher.attendance_percent
    ),
    homework: percentValue(
      teacher.homework_completion_percent
    ),
    results: percentValue(
      teacher.exam_performance_percent ||
        teacher.student_outcome_percent
    ),
  };
};

export default function TeachersPage() {
  const [teachers, setTeachers] =
    useState<Teacher[]>([]);
  const [search, setSearch] =
    useState("");
  const [showCreate, setShowCreate] =
    useState(false);
  const [form, setForm] =
    useState(initialTeacher);
  const [classes, setClasses] =
    useState<any[]>([]);
  const [sections, setSections] =
    useState<any[]>([]);
  const [subjects, setSubjects] =
    useState<any[]>([]);
  const [filters, setFilters] =
    useState({
      class_id: "",
      section_id: "",
      subject_id: "",
    });
  const [loading, setLoading] =
    useState(true);
  const [saving, setSaving] =
    useState(false);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async (
    nextFilters = filters
  ) => {
    try {
      setLoading(true);
      const teacherQuery =
        new URLSearchParams();
      Object.entries(nextFilters).forEach(
        ([key, value]) => {
          if (value) {
            teacherQuery.set(key, value);
          }
        }
      );
      const [rows, roster] =
        await Promise.all([
          apiJson<Teacher[]>(
            `/api/teachers${teacherQuery.toString() ? `?${teacherQuery.toString()}` : ""}`
          ),
          apiJson<any>("/api/roster"),
        ]);
      setTeachers(
        Array.isArray(rows) ? rows : []
      );
      setClasses(
        Array.isArray(roster.classes)
          ? roster.classes
          : []
      );
      setSections(
        Array.isArray(roster.sections)
          ? roster.sections
          : []
      );
      setSubjects(
        Array.isArray(roster.subjects)
          ? roster.subjects
          : []
      );
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to load teachers"
        )
      );
    } finally {
      setLoading(false);
    }
  };

  const createTeacher = async () => {
    try {
      setSaving(true);
      await apiJson("/api/teachers", {
        method: "POST",
        headers: {
          "Content-Type":
            "application/json",
        },
        body: JSON.stringify(form),
      });

      notify.success(
        "Teacher saved"
      );
      setForm(initialTeacher);
      setShowCreate(false);
      loadData();
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to save teacher"
        )
      );
    } finally {
      setSaving(false);
    }
  };

  const deleteTeacher = async (
    teacher: Teacher
  ) => {
    if (
      !confirm(
        `Delete ${fullName(teacher)} permanently? This will remove the teacher from the database.`
      )
    ) {
      return;
    }

    try {
      await apiJson(
        `/api/teachers/${teacher.id}`,
        {
          method: "DELETE",
        }
      );

      notify.success(
        "Teacher deleted from database"
      );
      loadData();
    } catch (error) {
      notify.error(
        errorMessage(
          error,
          "Failed to delete teacher"
        )
      );
    }
  };

  const filtered = useMemo(
    () =>
      teachers.filter((teacher) => {
        const text = `
          ${teacher.employee_id || ""}
          ${fullName(teacher)}
          ${teacher.phone || ""}
          ${teacher.email || ""}
          ${teacher.department || ""}
          ${teacher.designation || ""}
          ${teacher.class_name || ""}
          ${teacher.section_name || ""}
        `.toLowerCase();

        return text.includes(
          search.toLowerCase()
        );
      }),
    [teachers, search]
  );

  const filteredSections =
    sections.filter(
      (section) =>
        !form.class_id ||
        Number(section.class_id) ===
          Number(form.class_id)
    );
  const filteredFilterSections =
    sections.filter(
      (section) =>
        !filters.class_id ||
        Number(section.class_id) ===
          Number(filters.class_id)
    );

  return (
    <Layout>
      <div className="space-y-6">
        <div
          className="
            flex
            flex-col
            gap-4
            md:flex-row
            md:items-center
            md:justify-between
          "
        >
          <div className="min-w-0">
            <h1 className="text-3xl font-black md:text-4xl">
              Teachers
            </h1>
            <p className="mt-1 text-sm text-slate-600">
              Faculty Management Center
            </p>
          </div>

          <button
            onClick={() =>
              setShowCreate(
                (value) => !value
              )
            }
            className="tt-button inline-flex items-center justify-center gap-2"
          >
            <Plus size={17} />
            Add Teacher
          </button>
        </div>

        {showCreate && (
          <div className="tt-card tt-card-pad">
            <h2 className="mb-4 text-xl font-black">
              Create Teacher
            </h2>
            <div
              className="
                grid
                gap-4
                md:grid-cols-2
                xl:grid-cols-4
              "
            >
              {profileFields.map((key) => (
                <label
                  key={key}
                  className="min-w-0"
                >
                  <span className="mb-1 block text-sm font-bold capitalize text-slate-700">
                    {key.replaceAll(
                      "_",
                      " "
                    )}
                  </span>
                  <input
                    className="input"
                    value={
                      form[
                        key as keyof typeof form
                      ]
                    }
                    onChange={(event) =>
                      setForm(
                        (previous) => ({
                          ...previous,
                          [key]:
                            event.target
                              .value,
                        })
                      )
                    }
                  />
                </label>
              ))}
              <label className="min-w-0">
                <span className="mb-1 block text-sm font-bold text-slate-700">
                  Class
                </span>
                <select
                  className="input"
                  value={form.class_id}
                  onChange={(event) =>
                    setForm(
                      (previous) => ({
                        ...previous,
                        class_id:
                          event.target.value,
                        section_id: "",
                      })
                    )
                  }
                >
                  <option value="">
                    Select Class
                  </option>
                  {classes.map((item) => (
                    <option
                      key={item.id}
                      value={item.id}
                    >
                      {item.class_name}
                    </option>
                  ))}
                </select>
              </label>
              <label className="min-w-0">
                <span className="mb-1 block text-sm font-bold text-slate-700">
                  Subject
                </span>
                <select
                  className="input"
                  value={form.subject_id}
                  onChange={(event) =>
                    setForm(
                      (previous) => ({
                        ...previous,
                        subject_id:
                          event.target.value,
                      })
                    )
                  }
                >
                  <option value="">
                    Select Subject
                  </option>
                  {subjects.map((item) => (
                    <option
                      key={item.id}
                      value={item.id}
                    >
                      {item.subject_name}
                    </option>
                  ))}
                </select>
              </label>
              <label className="min-w-0">
                <span className="mb-1 block text-sm font-bold text-slate-700">
                  Section
                </span>
                <select
                  className="input"
                  value={form.section_id}
                  disabled={!form.class_id}
                  onChange={(event) =>
                    setForm(
                      (previous) => ({
                        ...previous,
                        section_id:
                          event.target.value,
                      })
                    )
                  }
                >
                  <option value="">
                    Select Section
                  </option>
                  {filteredSections.map(
                    (item) => (
                      <option
                        key={item.id}
                        value={item.id}
                      >
                        {item.section_name}
                      </option>
                    )
                  )}
                </select>
              </label>
              <label className="min-w-0">
                <span className="mb-1 block text-sm font-bold text-slate-700">
                  Assignment Type
                </span>
                <select
                  className="input"
                  value={
                    form.assignment_type
                  }
                  onChange={(event) =>
                    setForm(
                      (previous) => ({
                        ...previous,
                        assignment_type:
                          event.target.value,
                      })
                    )
                  }
                >
                  <option value="CLASS_TEACHER">
                    Class Teacher
                  </option>
                  <option value="SUBJECT_TEACHER">
                    Subject Teacher
                  </option>
                  <option value="MENTOR">
                    Mentor
                  </option>
                  <option value="SUPERVISOR">
                    Supervisor
                  </option>
                </select>
              </label>
            </div>
            <button
              onClick={createTeacher}
              disabled={saving}
              className="tt-button mt-5"
            >
              {saving
                ? "Saving..."
                : "Save Teacher"}
            </button>
          </div>
        )}

        <div className="tt-card tt-card-pad space-y-4">
          <input
            value={search}
            onChange={(event) =>
              setSearch(event.target.value)
            }
            placeholder="Search teacher, employee id, department, phone..."
            className="input"
          />
          <div className="grid gap-3 md:grid-cols-4">
            <select
              className="input"
              value={filters.class_id}
              onChange={(event) =>
                setFilters((previous) => ({
                  ...previous,
                  class_id:
                    event.target.value,
                  section_id: "",
                }))
              }
            >
              <option value="">All Classes</option>
              {classes.map((item) => (
                <option
                  key={item.id}
                  value={item.id}
                >
                  {item.class_name}
                </option>
              ))}
            </select>
            <select
              className="input"
              value={filters.section_id}
              disabled={!filters.class_id}
              onChange={(event) =>
                setFilters((previous) => ({
                  ...previous,
                  section_id:
                    event.target.value,
                }))
              }
            >
              <option value="">All Sections</option>
              {filteredFilterSections.map(
                (item) => (
                  <option
                    key={item.id}
                    value={item.id}
                  >
                    {item.section_name}
                  </option>
                )
              )}
            </select>
            <select
              className="input"
              value={filters.subject_id}
              onChange={(event) =>
                setFilters((previous) => ({
                  ...previous,
                  subject_id:
                    event.target.value,
                }))
              }
            >
              <option value="">All Subjects</option>
              {subjects.map((item) => (
                <option
                  key={item.id}
                  value={item.id}
                >
                  {item.subject_name}
                </option>
              ))}
            </select>
            <button
              className="tt-button"
              onClick={() =>
                loadData(filters)
              }
            >
              Apply Filters
            </button>
          </div>
        </div>

        {loading ? (
          <div className="tt-card tt-card-pad">
            Loading teachers...
          </div>
        ) : filtered.length === 0 ? (
          <div className="tt-card tt-card-pad">
            No teachers found for the selected school and academic year.
          </div>
        ) : (
          <div
            className="
              grid
              gap-4
              sm:grid-cols-2
              xl:grid-cols-3
              2xl:grid-cols-4
            "
          >
            {filtered.map((teacher) => (
              <article
                key={teacher.id}
                className="
                  tt-card
                  tt-card-pad
                  flex
                  min-h-[240px]
                  flex-col
                  justify-between
                  gap-5
                "
              >
                <div className="space-y-4">
                  {(() => {
                    const summary =
                      teacherPerformanceSummary(
                        teacher
                      );

                    return (
                      <div className="flex items-center justify-between gap-3 rounded-xl bg-slate-50 px-3 py-2">
                        <div>
                          <p className="text-[11px] font-black uppercase tracking-[0.14em] text-slate-500">
                            Performance
                          </p>
                          <p className="text-2xl font-black text-slate-950">
                            {summary.performance}%
                          </p>
                        </div>
                        <div className="text-right text-[11px] font-bold text-slate-500">
                          <p>
                            Attendance {summary.attendance}%
                          </p>
                          <p>
                            Homework {summary.homework}%
                          </p>
                          <p>
                            Student Results {summary.results}%
                          </p>
                        </div>
                      </div>
                    );
                  })()}

                  <div className="flex min-w-0 items-start gap-3">
                    <div
                      className="
                        grid
                        h-11
                        w-11
                        shrink-0
                        place-items-center
                        rounded-lg
                        border
                        border-amber-300/70
                        bg-slate-950
                        shadow-sm
                        text-amber-100
                      "
                      aria-hidden="true"
                    >
                      <UserRound
                        size={20}
                        strokeWidth={2.4}
                        className="text-amber-100"
                      />
                    </div>
                    <div className="min-w-0">
                      <h2 className="truncate text-lg font-black text-slate-950">
                        {fullName(teacher)}
                      </h2>
                      <p className="truncate text-sm font-semibold text-amber-700">
                        {teacher.employee_id ||
                          "No employee ID"}
                      </p>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-3 text-sm">
                    <Metric
                      label="Performance"
                      value={
                        teacher.performance_percent
                      }
                    />
                    <Metric
                      label="Attendance"
                      value={
                        teacher.attendance_percent
                      }
                    />
                    <Metric
                      label="Homework"
                      value={
                        teacher.homework_completion_percent
                      }
                    />
                    <Metric
                      label="Exam Outcome"
                      value={
                        teacher.exam_performance_percent
                      }
                    />
                    <Info
                      label="Department"
                      value={
                        teacher.department ||
                        "-"
                      }
                    />
                    <Info
                      label="Designation"
                      value={
                        teacher.designation ||
                        "-"
                      }
                    />
                    <Info
                      label="Academic Year"
                      value={
                        teacher.selected_academic_year ||
                        "Unassigned"
                      }
                    />
                    <Info
                      label="Class"
                      value={
                        teacher.class_name ||
                        "-"
                      }
                    />
                    <Info
                      label="Section"
                      value={
                        teacher.section_name ||
                        "-"
                      }
                    />
                    <Info
                      label="Email"
                      value={
                        teacher.email || "-"
                      }
                    />
                  </div>

                  <div
                    className="
                      flex
                      min-w-0
                      items-center
                      gap-2
                      rounded-lg
                      bg-slate-50
                      px-3
                      py-2
                      text-sm
                      text-slate-700
                    "
                  >
                    <Phone
                      size={15}
                      className="shrink-0"
                    />
                    <span className="truncate">
                      {teacher.phone ||
                        "No phone number"}
                    </span>
                  </div>
                </div>

                <div className="grid grid-cols-3 gap-2">
                  <ActionLink
                    href={`/teachers/${teacher.id}`}
                    label="View"
                    icon={<Eye size={15} />}
                  />
                  <ActionLink
                    href={`/teachers/edit/${teacher.id}`}
                    label="Edit"
                    icon={<Edit size={15} />}
                  />
                  <button
                    onClick={() =>
                      deleteTeacher(
                        teacher
                      )
                    }
                    className="
                      flex
                      min-w-0
                      items-center
                      justify-center
                      gap-1.5
                      rounded-lg
                      border
                      border-red-200
                      bg-red-50
                      px-3
                      py-2.5
                      text-sm
                      font-bold
                      text-red-700
                    "
                  >
                    <Trash2 size={15} />
                    <span className="truncate">
                      Delete
                    </span>
                  </button>
                </div>
              </article>
            ))}
          </div>
        )}
      </div>
    </Layout>
  );
}

function Info({
  label,
  value,
}: {
  label: string;
  value: string;
}) {
  return (
    <div className="min-w-0">
      <p className="text-xs font-bold uppercase text-slate-500">
        {label}
      </p>
      <p className="truncate font-semibold text-slate-950">
        {value}
      </p>
    </div>
  );
}

function Metric({
  label,
  value,
}: {
  label: string;
  value?: number | string | null;
}) {
  const number =
    Number(value ?? 0) || 0;

  return (
    <div className="rounded-lg border border-amber-100 bg-amber-50 px-3 py-2">
      <p className="text-[10px] font-black uppercase tracking-[0.12em] text-amber-800">
        {label}
      </p>
      <p className="mt-1 text-lg font-black text-slate-950">
        {number}%
      </p>
    </div>
  );
}

function ActionLink({
  href,
  label,
  icon,
}: {
  href: string;
  label: string;
  icon: ReactNode;
}) {
  return (
    <Link
      href={href}
      className="
        flex
        min-w-0
        items-center
        justify-center
        gap-1.5
        rounded-lg
        bg-slate-950
        px-3
        py-2.5
        text-sm
        font-bold
        text-white
      "
    >
      {icon}
      <span className="truncate">
        {label}
      </span>
    </Link>
  );
}
